import React, { useState, useEffect } from 'react';
import './EditablePriceTable.css';

export interface Product {
    id: number;
    name: string;
    currentPrice: number;
}

interface EditablePriceTableProps {
    products: Product[];
    onPriceUpdate: (productId: number, newPrice: number) => void;
    onDelete?: (productId: number) => void;
    validationFn?: (price: number) => boolean;
}

const EditablePriceTable: React.FC<EditablePriceTableProps> = ({
                                                                   products,
                                                                   onPriceUpdate,
                                                                   onDelete,
                                                                   validationFn,
                                                               }) => {
    const [drafts, setDrafts] = useState<Record<number, string>>({});

    useEffect(() => {
        // clear drafts for removed products
        setDrafts(prev => {
            const next: Record<number, string> = {};
            products.forEach(p => {
                if (prev[p.id] !== undefined) next[p.id] = prev[p.id];
            });
            return next;
        });
    }, [products]);

    const handleChange = (id: number, value: string) => {
        setDrafts(d => ({ ...d, [id]: value }));
    };

    const handleUpdate = (p: Product) => {
        const raw = drafts[p.id]?.trim();
        const num =
            raw === '' || raw === undefined ? p.currentPrice : parseFloat(raw);
        if (isNaN(num)) {
            alert('Please enter a valid number.');
            return;
        }
        if (validationFn && !validationFn(num)) {
            alert(`"${num}" is not valid.`);
            return;
        }
        onPriceUpdate(p.id, num);
        setDrafts(d => {
            const copy = { ...d };
            delete copy[p.id];
            return copy;
        });
    };

    return (
        <table className="price-table">
            <thead>
            <tr>
                <th>Product</th>
                <th>Current</th>
                <th>New Price</th>
                <th>Update</th>
                {onDelete && <th>Delete</th>}
            </tr>
            </thead>
            <tbody>
            {products.map(p => (
                <tr key={p.id}>
                    <td>{p.name}</td>
                    <td>${p.currentPrice.toFixed(2)}</td>
                    <td>
                        <input
                            type="number"
                            className="price-input"
                            value={drafts[p.id] ?? ''}
                            onChange={e => handleChange(p.id, e.target.value)}
                            placeholder={p.currentPrice.toFixed(2)}
                            step="0.01"
                        />
                    </td>
                    <td>
                        <button
                            className="update-btn"
                            onClick={() => handleUpdate(p)}
                        >
                            ✓
                        </button>
                    </td>
                    {onDelete && (
                        <td>
                            <button
                                className="delete-btn"
                                onClick={() => onDelete(p.id)}
                            >
                                🗑
                            </button>
                        </td>
                    )}
                </tr>
            ))}
            </tbody>
        </table>
    );
};

export default EditablePriceTable;
